import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

@app.tool()
def get_weather(location: str) -> str:
    logger.info(f"Tool called: get_weather(location={location})")

    try:
        result = fetch_weather_api(location)
        logger.info(f"Tool succeeded: {result}")
        return result
    except Exception as e:
        logger.error(f"Tool failed: {e}")
        raise

def call_tool(tool_name: str, arguments: dict):
    try:
        # Validate input
        validate_schema(arguments)

        # Execute tool
        result = execute_tool(tool_name, arguments)

        return result
    except ValidationError as e:
        # Structured validation error
        return {"error": "validation", "message": str(e)}
    except TimeoutError as e:
        # Structured timeout error
        return {"error": "timeout", "message": str(e)}
    except Exception as e:
        # Catch-all with logging
        logger.exception(f"Unexpected error: {e}")
        return {"error": "internal", "message": "Something went wrong"}
